create table dirkspzm32.pzm_zeiterfassung_eintraege (
    ze_rfid              varchar2(50 char) not null enable,
    ze_aktion            varchar2(3 char) not null enable,
    ze_datum             date not null enable,
    ze_geraet            varchar2(50 char) not null enable,
    ze_fa_auftrag        number(*, 0),
    ze_fa_ag             number(*, 0),
    ze_transfer_status   varchar2(3 char) not null enable,
    ze_ret_code          number(*, 0),
    ze_ret_msg           varchar2(255 char),
    created_date         date default sysdate not null enable,
    created_login_id     number(*, 0) default - 1 not null enable,
    last_change_date     date,
    last_change_login_id number(*, 0),
    ze_timezone_name     varchar2(50 char) default 'Europe/Berlin',
    quelle               varchar2(20 char) default 'TERMINAL',
    pers_nr              number(*, 0),
    ze_id                number(*, 0),
    ze_geraet_info       varchar2(1000 char),
    korr_ze_aktion       varchar2(3 char),
    korr_von_pers_nr     number(*, 0),
    korr_am              date,
    korr_grund           varchar2(255 char)
);

alter table dirkspzm32.pzm_zeiterfassung_eintraege
    add constraint pk_pzm_zeiterfassung_eintraege
        primary key ( ze_rfid,
                      ze_aktion,
                      ze_datum,
                      ze_geraet )
            using index enable;


